17	`ifndef __DEFINES_SVH
18	`define __DEFINES_SVH
19	
20	`include "config.svh"
21	
22	package defines;
23	
24	//
25	// Floating point types
26	//
27	
28	parameter FLOAT32_EXP_WIDTH = 8;
29	parameter FLOAT32_SIG_WIDTH = 23;
30	
31	// IEEE 754 Binary 32 encoding
32	typedef struct packed {
33	    logic sign;
34	    logic[FLOAT32_EXP_WIDTH - 1:0] exponent;
35	    logic[FLOAT32_SIG_WIDTH - 1:0] significand;
36	} float32_t;
37	
38	//
39	// Execution pipeline defines
40	//
41	
42	parameter NUM_VECTOR_LANES = 16;
43	parameter NUM_REGISTERS = 32;
44	parameter TOTAL_THREADS = `THREADS_PER_CORE * `NUM_CORES;
45	
46	typedef logic[31:0] scalar_t;
47	typedef scalar_t[NUM_VECTOR_LANES - 1:0] vector_t;
48	typedef logic[$clog2(`THREADS_PER_CORE) - 1:0] local_thread_idx_t;
49	typedef logic[`THREADS_PER_CORE - 1:0] local_thread_bitmap_t; // One bit per thread
50	typedef logic[4:0] register_idx_t;
51	typedef logic[$clog2(NUM_VECTOR_LANES) - 1:0] subcycle_t;
52	typedef logic[NUM_VECTOR_LANES - 1:0] vector_mask_t;
53	typedef logic[14:0] syscall_index_t;
54	
55	parameter CORE_ID_WIDTH = $clog2(`NUM_CORES);
56	
57	// The width of core_id_t is hardcoded to work around some tool issues.
58	// For one core, CORE_ID_WIDTH will be 0, but if I made the range
59	// [CORE_ID_WIDTH - 1:0], the range would be [-1:0], which is invalid. I tried
60	// defining CORE_ID_WIDTH as (`NUM_CORES == 1 ? 1 : $clog2(`NUM_CORES)), which
61	// works fine on many tools, but crashes Synopsys Design Compiler. This limits
62	// to 16 cores. To synthesize more, increase this width.
63	// XXX CORE_ID_WIDTH was previously a `define. the workaround above may work
64	// now that it is a parameter, but I haven't tested.
65	typedef logic[3:0] core_id_t;
66	
67	// CORE_PERF_EVENTS should match the number of signals in the assignment to
68	// core_perf_events in core.sv and L2_PERF_EVENTS must match the number of
69	// signals in the assignment to l2_perf_events in l2_cache.sv.
70	parameter CORE_PERF_EVENTS = 14;
71	parameter L2_PERF_EVENTS = 3;
72	
73	//
74	// Instruction encodings
75	//
76	
77	parameter INSTRUCTION_NOP = 32'd0;
78	parameter REG_RA = register_idx_t'(31);
79	
80	// Immediate/register arithmetic operation encodings
81	typedef enum logic[5:0] {
82	    OP_OR                   = 6'b000000,    // Bitwise logical or
83	    OP_AND                  = 6'b000001,    // bitwise logical and
84	    OP_SYSCALL              = 6'b000010,    // raise syscall trap
85	    OP_XOR                  = 6'b000011,    // bitwise logical exclusive or
86	    OP_ADD_I                = 6'b000101,    // Add integer
87	    OP_SUB_I                = 6'b000110,    // Subtract integer
88	    OP_MULL_I               = 6'b000111,    // Multiply integer low
89	    OP_MULH_U               = 6'b001000,    // Unsigned multiply, return high bits
90	    OP_ASHR                 = 6'b001001,    // Arithmetic shift right (sign extend)
91	    OP_SHR                  = 6'b001010,    // Logical shift right (no sign extend)
92	    OP_SHL                  = 6'b001011,    // Logical shift left
93	    OP_CLZ                  = 6'b001100,    // Count leading zeroes
94	    OP_SHUFFLE              = 6'b001101,    // Shuffle vector lanes
95	    OP_CTZ                  = 6'b001110,    // Count trailing zeroes
96	    OP_MOVE                 = 6'b001111,
97	    OP_CMPEQ_I              = 6'b010000,    // Integer equal
98	    OP_CMPNE_I              = 6'b010001,    // Integer not equal
99	    OP_CMPGT_I              = 6'b010010,    // Integer greater (signed)
100	    OP_CMPGE_I              = 6'b010011,    // Integer greater or equal (signed)
101	    OP_CMPLT_I              = 6'b010100,    // Integer less than (signed)
102	    OP_CMPLE_I              = 6'b010101,    // Integer less than or equal (signed)
103	    OP_CMPGT_U              = 6'b010110,    // Integer greater than (unsigned)
104	    OP_CMPGE_U              = 6'b010111,    // Integer greater or equal (unsigned)
105	    OP_CMPLT_U              = 6'b011000,    // Integer less than (unsigned)
106	    OP_CMPLE_U              = 6'b011001,    // Integer less than or equal (unsigned)
107	    OP_GETLANE              = 6'b011010,    // Getlane
108	    OP_FTOI                 = 6'b011011,    // Float to integer
109	    OP_RECIPROCAL           = 6'b011100,    // Reciprocal estimate
110	    OP_SEXT8                = 6'b011101,    // Sign extend 8 bit value
111	    OP_SEXT16               = 6'b011110,    // Sign extend 16 bit value
112	    OP_MULH_I               = 6'b011111,    // Signed multiply high
113	    OP_ADD_F                = 6'b100000,    // Add floating point
114	    OP_SUB_F                = 6'b100001,    // Subtract floating point
115	    OP_MUL_F                = 6'b100010,    // Multiply floating point
116	    OP_ITOF                 = 6'b101010,    // Integer to float
117	    OP_CMPGT_F              = 6'b101100,    // Floating point greater than
118	    OP_CMPLT_F              = 6'b101110,    // Floating point less than
119	    OP_CMPGE_F              = 6'b101101,    // Floating point greater or equal
120	    OP_CMPLE_F              = 6'b101111,    // Floating point less than or equal
121	    OP_CMPEQ_F              = 6'b110000,    // Floating point equal
122	    OP_CMPNE_F              = 6'b110001,    // Floating point not-equal
123	    OP_BREAKPOINT           = 6'b111110
124	} alu_op_t;
125	
126	// Operation type field encodings for memory instructions
127	typedef enum logic[3:0] {
128	    MEM_B                   = 4'b0000,  // Byte (8 bit)
129	    MEM_BX                  = 4'b0001,  // Byte, sign extended
130	    MEM_S                   = 4'b0010,  // Short (16 bit)
131	    MEM_SX                  = 4'b0011,  // Short, sign extended
132	    MEM_L                   = 4'b0100,  // Long (32 bit)
133	    MEM_SYNC                = 4'b0101,  // Synchronized
134	    MEM_CONTROL_REG         = 4'b0110,  // Control register
135	    MEM_BLOCK               = 4'b0111,  // Vector block
136	    MEM_BLOCK_M             = 4'b1000,
137	    MEM_SCGATH              = 4'b1101,  // Vector scatter/gather
138	    MEM_SCGATH_M            = 4'b1110
139	} memory_op_t;
140	
141	// Operation type field encodings for cache control instructions
142	typedef enum logic[2:0] {
143	    CACHE_DTLB_INSERT       = 3'b000,
144	    CACHE_DINVALIDATE       = 3'b001,
145	    CACHE_DFLUSH            = 3'b010,
146	    CACHE_IINVALIDATE       = 3'b011,
147	    CACHE_MEMBAR            = 3'b100,
148	    CACHE_TLB_INVAL         = 3'b101,
149	    CACHE_TLB_INVAL_ALL     = 3'b110,
150	    CACHE_ITLB_INSERT       = 3'b111
151	} cache_op_t;
152	
153	// Operation type field encodings for branch instructions
154	typedef enum logic[2:0] {
155	    BRANCH_REGISTER         = 3'b000,
156	    BRANCH_ZERO             = 3'b001,
157	    BRANCH_NOT_ZERO         = 3'b010,
158	    BRANCH_ALWAYS           = 3'b011,
159	    BRANCH_CALL_OFFSET      = 3'b100,
160	    BRANCH_CALL_REGISTER    = 3'b110,
161	    BRANCH_ERET             = 3'b111
162	} branch_type_t;
163	
164	// Control register indices
165	typedef enum logic [4:0] {
166	    CR_THREAD_ID            = 5'd0,
167	    CR_TRAP_HANDLER         = 5'd1,
168	    CR_TRAP_PC              = 5'd2,
169	    CR_TRAP_CAUSE           = 5'd3,
170	    CR_FLAGS                = 5'd4,
171	    CR_TRAP_ADDRESS         = 5'd5,
172	    CR_CYCLE_COUNT          = 5'd6,
173	    CR_TLB_MISS_HANDLER     = 5'd7,
174	    CR_SAVED_FLAGS          = 5'd8,
175	    CR_CURRENT_ASID         = 5'd9,
176	    CR_PAGE_DIR             = 5'd10,
177	    CR_SCRATCHPAD0          = 5'd11,
178	    CR_SCRATCHPAD1          = 5'd12,
179	    CR_SUBCYCLE             = 5'd13,
180	    CR_INTERRUPT_ENABLE     = 5'd14,
181	    CR_INTERRUPT_ACK        = 5'd15,
182	    CR_INTERRUPT_PENDING    = 5'd16,
183	    CR_INTERRUPT_TRIGGER    = 5'd17,
184	    CR_JTAG_DATA            = 5'd18,
185	    CR_SYSCALL_INDEX        = 5'd19,
186	    CR_SUSPEND_THREAD       = 5'd20,
187	    CR_RESUME_THREAD        = 5'd21,
188	    CR_PERF_EVENT_SELECT0   = 5'd22,
189	    CR_PERF_EVENT_SELECT1   = 5'd23,
190	    CR_PERF_EVENT_COUNT0_L  = 5'd24,
191	    CR_PERF_EVENT_COUNT0_H  = 5'd25,
192	    CR_PERF_EVENT_COUNT1_L  = 5'd26,
193	    CR_PERF_EVENT_COUNT1_H  = 5'd27
194	} control_register_t;
195	
196	// Trap type encodings
197	typedef enum logic[3:0] {
198	    TT_RESET                = 4'd0,
199	    TT_ILLEGAL_INSTRUCTION  = 4'd1,
200	    TT_PRIVILEGED_OP        = 4'd2,
201	    TT_INTERRUPT            = 4'd3,
202	    TT_SYSCALL              = 4'd4,
203	    TT_UNALIGNED_ACCESS     = 4'd5,
204	    TT_PAGE_FAULT           = 4'd6,
205	    TT_TLB_MISS             = 4'd7,
206	    TT_ILLEGAL_STORE        = 4'd8,
207	    TT_SUPERVISOR_ACCESS    = 4'd9,
208	    TT_NOT_EXECUTABLE       = 4'd10,
209	    TT_BREAKPOINT           = 4'd11
210	} trap_type_t;
211	
212	//
213	// Decoded instruction fields
214	//
215	
216	typedef enum logic [1:0] {
217	    MASK_SRC_SCALAR1,
218	    MASK_SRC_SCALAR2,
219	    MASK_SRC_ALL_ONES
220	} mask_src_t;
221	
222	typedef enum logic {
223	    OP1_SRC_VECTOR1,
224	    OP1_SRC_SCALAR1
225	} op1_src_t;
226	
227	typedef enum logic [1:0] {
228	    OP2_SRC_SCALAR2,
229	    OP2_SRC_VECTOR2,
230	    OP2_SRC_IMMEDIATE
231	} op2_src_t;
232	
233	typedef enum logic [1:0] {
234	    PIPE_MEM,
235	    PIPE_INT_ARITH,
236	    PIPE_FLOAT_ARITH
237	} pipeline_sel_t;
238	
239	typedef struct packed {
240	    logic dcache;
241	    logic store;
242	    trap_type_t trap_type;
243	} trap_cause_t;
244	
245	typedef logic[3:0] interrupt_id_t;
246	
247	typedef struct packed {
248	    scalar_t pc;
249	
250	    // Was this instruction injected by the on-chip debugger
251	    logic injected;
252	
253	    // Piggybacked exceptions
254	    logic has_trap;
255	    trap_cause_t trap_cause;
256	
257	    // Decoded instruction fields
258	    logic has_scalar1;
259	    register_idx_t scalar_sel1;
260	    logic has_scalar2;
261	    register_idx_t scalar_sel2;
262	    logic has_vector1;
263	    register_idx_t vector_sel1;
264	    logic has_vector2;
265	    register_idx_t vector_sel2;
266	    logic has_dest;
267	    logic dest_vector;
268	    register_idx_t dest_reg;
269	    alu_op_t alu_op;
270	    mask_src_t mask_src;
271	    op1_src_t op1_src;
272	    op2_src_t op2_src;
273	    logic store_value_vector;
274	    scalar_t immediate_value;
275	    logic branch;
276	    branch_type_t branch_type;
277	    logic call;
278	    pipeline_sel_t pipeline_sel;
279	    logic memory_access;
280	    memory_op_t memory_access_type;
281	    logic load;
282	    logic compare;
283	    subcycle_t last_subcycle; // count of last subcycle, not a boolean flag
284	    control_register_t creg_index;
285	    logic cache_control;
286	    cache_op_t cache_control_op;
287	} decoded_instruction_t;
288	
289	//
290	// Cache defines
291	//
292	
293	parameter PAGE_SIZE = 'h1000;
294	parameter PAGE_NUM_BITS  = 32 - $clog2(PAGE_SIZE);
295	parameter ASID_WIDTH = 8;
296	parameter CACHE_LINE_BYTES = NUM_VECTOR_LANES * 4; // Must be same as vector width
297	parameter CACHE_LINE_BITS = CACHE_LINE_BYTES * 8;
298	parameter CACHE_LINE_WORDS = CACHE_LINE_BYTES / 4;
299	parameter CACHE_LINE_OFFSET_WIDTH = $clog2(CACHE_LINE_BYTES);    // Byte offset into a cache line
300	parameter ICACHE_TAG_BITS = 32 - (CACHE_LINE_OFFSET_WIDTH + $clog2(`L1I_SETS));
301	parameter DCACHE_TAG_BITS = 32 - (CACHE_LINE_OFFSET_WIDTH + $clog2(`L1D_SETS));
302	
303	typedef logic[CACHE_LINE_BITS - 1:0] cache_line_data_t;
304	typedef logic[PAGE_NUM_BITS - 1:0] page_index_t;
305	
306	typedef struct packed {
307	    logic[PAGE_NUM_BITS - 1:0] ppage_idx;
308	    logic[32 - (PAGE_NUM_BITS + 5) - 1:0] unused;
309	    logic global_map;
310	    logic supervisor;
311	    logic executable;
312	    logic writable;
313	    logic present;
314	} tlb_entry_t;
315	
316	typedef logic[$clog2(`L1D_WAYS) - 1:0] l1d_way_idx_t;
317	typedef logic[$clog2(`L1D_SETS) - 1:0] l1d_set_idx_t;
318	typedef logic[DCACHE_TAG_BITS - 1:0] l1d_tag_t;
319	
320	typedef struct packed {
321	    l1d_tag_t tag;
322	    l1d_set_idx_t set_idx;
323	    logic[CACHE_LINE_OFFSET_WIDTH - 1:0] offset;
324	} l1d_addr_t;
325	
326	typedef logic[$clog2(`L1I_WAYS) - 1:0] l1i_way_idx_t;
327	typedef logic[$clog2(`L1I_SETS) - 1:0] l1i_set_idx_t;
328	typedef logic[ICACHE_TAG_BITS - 1:0] l1i_tag_t;
329	
330	typedef struct packed {
331	    l1i_tag_t tag;
332	    l1i_set_idx_t set_idx;
333	    logic[CACHE_LINE_OFFSET_WIDTH - 1:0] offset;
334	} l1i_addr_t;
335	
336	typedef logic[$clog2(`L2_WAYS) - 1:0] l2_way_idx_t;
337	typedef logic[$clog2(`L2_SETS) - 1:0] l2_set_idx_t;
338	typedef logic[(31 - (CACHE_LINE_OFFSET_WIDTH + $clog2(`L2_SETS))):0] l2_tag_t;
339	typedef struct packed {
340	    l2_tag_t tag;
341	    l2_set_idx_t set_idx;
342	} l2_addr_t;
343	
344	// Memory address expressed as multiple of cache line size
345	typedef logic[31 - CACHE_LINE_OFFSET_WIDTH:0] cache_line_index_t;
346	
347	typedef enum logic {
348	    CT_ICACHE,
349	    CT_DCACHE
350	} cache_type_t;
351	
352	typedef logic[$clog2(`THREADS_PER_CORE) - 1:0] l1_miss_entry_idx_t;
353	
354	typedef enum logic[2:0] {
355	    L2REQ_LOAD,
356	    L2REQ_LOAD_SYNC,
357	    L2REQ_STORE,
358	    L2REQ_STORE_SYNC,
359	    L2REQ_FLUSH,
360	    L2REQ_IINVALIDATE,
361	    L2REQ_DINVALIDATE
362	} l2req_packet_type_t;
363	
364	// L2 request
365	typedef struct packed {
366	    core_id_t core;
367	    l1_miss_entry_idx_t id;
368	    l2req_packet_type_t packet_type;
369	    cache_type_t cache_type;
370	    l2_addr_t address;
371	    logic[CACHE_LINE_BYTES - 1:0] store_mask;
372	    cache_line_data_t data;
373	} l2req_packet_t;
374	
375	typedef enum logic[2:0] {
376	    L2RSP_LOAD_ACK,
377	    L2RSP_STORE_ACK,
378	    L2RSP_FLUSH_ACK,
379	    L2RSP_IINVALIDATE_ACK,
380	    L2RSP_DINVALIDATE_ACK
381	} l2rsp_packet_type_t;
382	
383	// L2 response
384	typedef struct packed {
385	    logic status;
386	    core_id_t core;
387	    l1_miss_entry_idx_t id;
388	    l2rsp_packet_type_t packet_type;
389	    cache_type_t cache_type;
390	    l2_addr_t address;
391	    cache_line_data_t data;
392	} l2rsp_packet_t;
393	
394	// I/O bus request
395	typedef struct packed {
396	    logic store;
397	    local_thread_idx_t thread_idx;
398	    scalar_t address;
399	    scalar_t value;
400	} ioreq_packet_t;
401	
402	// I/O bus response
403	typedef struct packed {
404	    core_id_t core;
405	    local_thread_idx_t thread_idx;
406	    scalar_t read_value;
407	} iorsp_packet_t;
408	
409	parameter AXI_ADDR_WIDTH = 32;
410	
411	endpackage : defines
412	
413	// Non-cached I/O bus (peripheral register access) external interface
414	// write_en and read_en are mutually exclusive. When read_en is asserted, the
415	// data will appear on read_data one cycle later.
416	interface io_bus_interface;
417	    logic write_en;
418	    logic read_en;
419	    defines::scalar_t address;
420	    defines::scalar_t write_data;
421	    defines::scalar_t read_data;
422	
423	    modport master(output write_en, read_en, address, write_data, input read_data);
424	    modport slave(input write_en, read_en, address, write_data, output read_data);
425	endinterface
426	
427	// AMBA AXI-4 bus interface
428	// See table A10-1 and A10-3 for default values of optional signals not included here.
429	interface axi4_interface;
430	    // Global signals (Table A2-1)
431	    logic m_aclk;
432	    logic m_aresetn;
433	
434	    // Write address channel (Table A2-2)
435	    logic [AXI_ADDR_WIDTH - 1:0] m_awaddr;
436	    logic [7:0] m_awlen;
437	    logic [2:0] m_awprot;
438	    logic m_awvalid;
439	    logic s_awready;
440	
441	    // Write data channel (Table A2-3)
442	    logic [`AXI_DATA_WIDTH - 1:0] m_wdata;
443	    logic m_wlast;
444	    logic m_wvalid;
445	    logic s_wready;
446	
447	    // Write response channel (Table A2-4)
448	    logic s_bvalid;
449	    logic m_bready;
450	
451	    // Read address channel (Table A2-5)
452	    logic [AXI_ADDR_WIDTH - 1:0] m_araddr;
453	    logic [7:0] m_arlen;
454	    logic [2:0] m_arprot;
455	    logic m_arvalid;
456	    logic s_arready;
457	
458	    // Read data channel (Table A2-6)
459	    logic [`AXI_DATA_WIDTH - 1:0] s_rdata;
460	    logic s_rvalid;
461	    logic m_rready;
462	
463	    modport master(input s_awready, s_wready, s_bvalid, s_arready, s_rvalid, s_rdata,
464	        output m_awaddr, m_awlen, m_awvalid, m_wdata, m_wlast, m_wvalid, m_bready, m_araddr,
465	        m_arlen, m_arvalid, m_rready, m_aclk, m_aresetn, m_arprot, m_awprot);
466	    modport slave(input m_awaddr, m_awlen, m_awvalid, m_wdata, m_wlast, m_wvalid, m_bready,
467	        m_araddr, m_arlen, m_arvalid, m_rready, m_aclk, m_aresetn, m_arprot, m_awprot,
468	        output s_awready, s_wready, s_bvalid, s_arready, s_rvalid, s_rdata);
469	endinterface
470	
471	interface jtag_interface;
472	    logic tck;
473	    logic trst_n;
474	    logic tdi;
475	    logic tdo;
476	    logic tms;
477	
478	    modport host(input tdi, output tck, trst_n, tdo, tms);
479	    modport target(input tck, trst_n, tdi, tms, output tdo);
480	endinterface
481	
482	`endif
